const style = `
@keyframes blink {
    0%, 98%, 100% { transform: scaleY(1) rotate(0deg); }
    99% { transform: scaleY(0.1) rotate(90deg); }
}

@keyframes mouthClose {
    0%, 70% { transform: scaleY(1) rotate(0deg); }
    80% { transform: scaleY(0.3) rotate(-15deg); }
    90% { transform: scaleY(0.3) rotate(-10deg); }
    100% { transform: scaleY(1) rotate(0deg); }
}

@keyframes activeWiggle {
    0%, 100% { transform: rotate(0deg) translateY(0px); }
    25% { transform: rotate(-5deg) translateY(-1px); }
    50% { transform: rotate(0deg) translateY(-3px); }
    75% { transform: rotate(5deg) translateY(-1px); }
}

@keyframes pulse {
    0%, 100% { opacity: 0.3; }
    50% { opacity: 1; }
}

#left-eye {
    animation: blink 5s infinite;
    transform-origin: center center;
    transform-box: fill-box;
}

#right-eye {
    animation: blink 5s infinite;
    transform-origin: center center;
    transform-box: fill-box;
}

#mouth {
    animation: mouthClose 8s infinite ease-in-out;
    transform-origin: center center;
    transform-box: fill-box;
}

#cloud {
    animation: activeWiggle 5s infinite ease-in-out;
    transform-origin: bottom left;
    transform-box: fill-box;
    animation-delay: 0.5s;
}

#cloud-dots {
    animation: pulse 1.2s infinite ease-in-out;
}
`

